    D4D Mission Metabolism
  .app-shell,
.boot-screen {
  min-height: 100dvh;
  background: var(--surface-base);
}

.app-shell {
  padding: var(--space-4);
}

.boot-screen {
  display: grid;
  place-items: center;
}

.boot-panel,
.panel,
.recommendation-card {
  border: 1px solid var(--border-subtle);
  background: var(--surface-panel);
  border-radius: 8px;
}

.boot-panel {
  display: flex;
  align-items: center;
  gap: var(--space-3);
  padding: var(--space-4) var(--space-5);
  color: var(--text-secondary);
}

.pulse-dot {
  width: 9px;
  height: 9px;
  border-radius: 8px;
  background: var(--status-success);
}

.mission-bar,
.metric-strip,
.workspace,
.custom-workspace {
  max-width: 1480px;
  margin: 0 auto;
}

.mission-bar {
  display: grid;
  grid-template-columns: minmax(220px, 296px) minmax(320px, 1fr) auto;
  gap: var(--space-4);
  align-items: center;
  padding: var(--space-4) 0 var(--space-3);
  border-bottom: 1px solid var(--border-subtle);
}

.toolbar,
.metric-heading,
.panel-title,
.area-header,
.capability-label,
.decision-row,
.map-legend,
.card-heading {
  display: flex;
  align-items: center;
}

.toolbar,
.metric-heading,
.decision-row {
  gap: var(--space-2);
}

.mission-title {
  display: grid;
  gap: var(--space-1);
}

.mission-clock,
.mission-constraints,
.metric-context {
  color: var(--text-muted);
  font-size: 12px;
  line-height: 1.35;
  font-variant-numeric: tabular-nums;
}

.mission-clock {
  font-family:
    Cascadia Mono,
    Berkeley Mono,
    ui-monospace,
    monospace;
}

.mission-intent {
  display: grid;
  gap: var(--space-1);
  min-width: 0;
  padding: 0 var(--space-4);
  border-inline: 1px solid var(--border-subtle);
}

.mission-objective {
  overflow: hidden;
  color: var(--text-secondary);
  text-overflow: ellipsis;
  white-space: nowrap;
}

h1,
h2,
h3,
p {
  margin: 0;
}

h1 {
  font-size: 22px;
  line-height: 1.15;
  font-weight: 590;
}

h3 {
  font-size: 16px;
  line-height: 1.35;
}

.caption,
.mono,
.severity,
.status-pill,
.chip,
.kind {
  font-size: 12px;
  line-height: 1.35;
}

.mono {
  font-family:
    Cascadia Mono,
    Berkeley Mono,
    ui-monospace,
    SFMono-Regular,
    Menlo,
    monospace;
}

.caption,
.empty-state {
  color: var(--text-muted);
}

.button {
  display: inline-flex;
  align-items: center;
  justify-content: center;
  gap: var(--space-2);
  min-height: 34px;
  padding: 0 var(--space-3);
  border: 1px solid var(--border-strong);
  border-radius: 6px;
  background: var(--surface-command);
  color: var(--text-secondary);
  cursor: pointer;
  transition:
    border-color 180ms ease-in-out,
    color 180ms ease-in-out,
    background 180ms ease-in-out;
}

.button:hover:not(:disabled) {
  background: var(--surface-hover);
  border-color: var(--accent-primary);
}

.button:active:not(:disabled) {
  background: var(--surface-inset);
}

.button:focus-visible,
.blackbox-row:focus-visible {
  outline: 2px solid var(--accent-hover);
  outline-offset: 2px;
}

.button:disabled {
  opacity: 0.45;
  cursor: not-allowed;
}

.button.primary {
  border-color: var(--accent-primary);
  color: var(--surface-base);
  background: var(--accent-primary);
}

.button.primary:hover:not(:disabled) {
  border-color: var(--accent-hover);
  background: var(--accent-hover);
}

.button.primary:disabled {
  border-color: var(--border-subtle);
  background: var(--surface-command);
  color: var(--text-muted);
}

.button.danger {
  color: var(--status-danger);
}

.error-banner {
  max-width: 1480px;
  margin: 0 auto var(--space-3);
  padding: var(--space-3);
  border: 1px solid color-mix(in srgb, var(--status-danger) 45%, transparent);
  border-radius: 8px;
  color: var(--status-danger);
  background: color-mix(in srgb, var(--status-danger) 12%, transparent);
}

.metric-heading,
.panel-title {
  justify-content: space-between;
  color: var(--text-secondary);
}

.success,
.satisfied {
  color: var(--status-success);
}

.warning,
.strained {
  color: var(--status-warning);
}

.danger,
.deficit,
.critical {
  color: var(--status-danger);
}

.info {
  color: var(--status-info);
}

.sr-only {
  position: absolute;
  width: 1px;
  height: 1px;
  overflow: hidden;
  clip-path: inset(50%);
  white-space: nowrap;
}

.workspace-tabs {
  display: flex;
  align-items: center;
  justify-content: flex-start;
  max-width: 1480px;
  margin: var(--space-4) auto 0;
  gap: var(--space-2);
  padding: var(--space-2);
  border: 1px solid var(--border-subtle);
  border-radius: 8px;
  background: var(--surface-panel);
}

.workspace-tab {
  display: grid;
  gap: 1px;
  min-width: 160px;
  min-height: 46px;
  padding: var(--space-2) var(--space-3);
  border: 1px solid transparent;
  border-radius: 6px;
  background: transparent;
  color: var(--text-muted);
  cursor: pointer;
  text-align: left;
}

.workspace-tab span {
  color: var(--text-secondary);
  font-size: 13px;
  line-height: 1.25;
}

.workspace-tab small {
  font-size: 12px;
  line-height: 1.25;
}

.workspace-tab.active {
  border-color: var(--accent-primary);
  background: var(--surface-elevated);
  color: var(--text-secondary);
}

.workspace-tab.active span {
  color: var(--text-primary);
}

.workspace-tab:focus-visible {
  outline: 2px solid var(--accent-hover);
  outline-offset: 2px;
}

.metric-strip {
  display: grid;
  grid-template-columns: repeat(4, minmax(0, 1fr));
  overflow: hidden;
  margin-top: var(--space-3);
  border: 1px solid var(--border-subtle);
  border-radius: 8px;
  background: var(--surface-panel);
}

.metric-card {
  display: grid;
  gap: var(--space-1);
  padding: var(--space-4);
  border-right: 1px solid var(--border-subtle);
  background: transparent;
}

.metric-card:last-child {
  border-right: 0;
}

.metric-value {
  display: block;
  margin-top: var(--space-1);
  font-size: 26px;
  line-height: 1.1;
  font-variant-numeric: tabular-nums;
}

.meter {
  display: block;
  width: 100%;
  height: 7px;
  overflow: hidden;
  border-radius: 999px;
  border: 0;
  appearance: none;
  margin-top: var(--space-2);
  background: var(--rail-muted);
}

.meter::-webkit-meter-bar {
  border: 0;
  border-radius: inherit;
  background: var(--rail-muted);
}

.meter::-webkit-meter-optimum-value,
.meter::-webkit-meter-suboptimum-value,
.meter::-webkit-meter-even-less-good-value {
  border-radius: inherit;
  background: currentColor;
}

.meter::-moz-meter-bar {
  border-radius: inherit;
  background: currentColor;
}

.event-grid {
  display: grid;
  gap: var(--space-2);
  margin-top: var(--space-3);
}

.event-form {
  display: grid;
  gap: var(--space-2);
  margin-top: var(--space-3);
}

.event-form .button {
  width: 100%;
}

.event-button {
  display: grid;
  grid-template-columns: 22px minmax(0, 1fr);
  justify-content: stretch;
  justify-items: start;
  min-height: 46px;
  padding: var(--space-2) var(--space-3);
  text-align: left;
}

.event-button svg {
  align-self: center;
  justify-self: center;
}

.event-copy {
  display: grid;
  min-width: 0;
  gap: 2px;
}

.event-copy > span {
  overflow: hidden;
  line-height: 1.25;
  text-overflow: ellipsis;
  white-space: nowrap;
}

.deployment-panel {
  display: grid;
  gap: var(--space-3);
}

.deployment-list {
  display: grid;
  gap: var(--space-2);
}

.deployment-row {
  display: grid;
  grid-template-columns: 28px minmax(0, 1fr) auto;
  gap: var(--space-2);
  align-items: center;
  padding: var(--space-2);
  border: 1px solid var(--border-subtle);
  border-radius: 6px;
  background: var(--surface-inset);
}

.deployment-vehicle-icon {
  width: 24px;
  height: 24px;
  justify-self: center;
  object-fit: contain;
  border-radius: 4px;
  background: var(--surface-base);
}

.deployment-copy {
  display: grid;
  min-width: 0;
}

.deployment-copy strong,
.deployment-copy small {
  min-width: 0;
  overflow: hidden;
  text-overflow: ellipsis;
  white-space: nowrap;
}

.deployment-copy strong {
  color: var(--text-secondary);
  font-size: 12px;
  font-weight: 590;
  line-height: 1.25;
}

.deployment-copy small {
  color: var(--text-muted);
  font-size: 11px;
  line-height: 1.25;
}

.deployment-stepper {
  display: grid;
  grid-template-columns: 30px 44px 30px;
  gap: var(--space-1);
}

.deployment-stepper .button {
  min-height: 30px;
  padding: 0;
}

.deployment-stepper input {
  width: 44px;
  min-width: 0;
  border: 1px solid var(--border-subtle);
  border-radius: 6px;
  background: var(--surface-base);
  color: var(--text-primary);
  font: inherit;
  text-align: center;
}

.deployment-actions {
  display: flex;
  gap: var(--space-2);
  align-items: center;
  justify-content: space-between;
}

.deployment-warning {
  color: var(--status-warning);
}

.deployment-subtitle {
  display: flex;
  gap: var(--space-2);
  align-items: center;
  justify-content: space-between;
  color: var(--text-secondary);
  font-size: 12px;
  font-weight: 590;
}

.deployed-assets,
.deployed-asset-list {
  display: grid;
  gap: var(--space-2);
}

.deployed-assets {
  min-inline-size: 0;
  margin: 0;
  padding: 0;
  border: 0;
}

.deployed-asset-list {
  max-height: 360px;
  overflow: auto;
  padding-right: 2px;
}

.deployed-asset-row {
  display: grid;
  grid-template-columns: 28px minmax(0, 1fr) 30px;
  gap: var(--space-2);
  align-items: center;
  padding: var(--space-2);
  border: 1px solid var(--border-subtle);
  border-radius: 6px;
  background: color-mix(in srgb, var(--surface-inset) 82%, var(--surface-panel));
}

.deployed-asset-remove {
  min-height: 30px;
  padding: 0;
}

.vehicle-param-controls {
  display: grid;
  grid-column: 1 / -1;
  grid-template-columns: repeat(2, minmax(0, 1fr));
  gap: var(--space-2);
  padding-top: var(--space-2);
  border-top: 1px solid var(--border-subtle);
}

.vehicle-param-field {
  display: grid;
  grid-template-columns: auto minmax(0, 1fr) 34px;
  gap: var(--space-2);
  align-items: center;
  min-width: 0;
  color: var(--text-muted);
  font-size: 11px;
}

.vehicle-param-field span,
.vehicle-param-field b {
  white-space: nowrap;
}

.vehicle-param-field b {
  color: var(--text-secondary);
  font-weight: 590;
  text-align: right;
}

.vehicle-param-field input[type="range"] {
  width: 100%;
  min-width: 0;
  accent-color: var(--accent-primary);
}

.vehicle-param-field select {
  grid-column: 2 / 4;
  width: 100%;
  min-width: 0;
  min-height: 30px;
  padding: 0 var(--space-2);
  border: 1px solid var(--border-subtle);
  border-radius: 6px;
  background: var(--surface-base);
  color: var(--text-primary);
  font: inherit;
}

.vehicle-param-apply {
  grid-column: 1 / -1;
  justify-content: center;
  min-height: 30px;
}

.workspace {
  display: grid;
  grid-template-columns: 296px minmax(520px, 1fr) 388px;
  gap: var(--space-4);
  margin-top: var(--space-4);
}

.left-rail,
.center-stage,
.right-rail,
.area-stack,
.recommendation-list {
  display: grid;
  gap: var(--space-4);
  align-content: start;
}

.panel {
  min-width: 0;
  padding: var(--space-4);
}

.panel-title {
  min-height: 24px;
}

.panel-title h2 {
  margin: 0;
  color: var(--text-primary);
  font-size: 14px;
  font-weight: 650;
  line-height: 1.2;
}

.log-workspace {
  display: grid;
  max-width: 1040px;
  margin: var(--space-4) auto 0;
}

.area-stack {
  margin-top: var(--space-3);
}

.area-card,
.comparison-card,
.ccr-band {
  padding: var(--space-3);
  border: 1px solid var(--border-subtle);
  border-radius: 8px;
  background: var(--surface-inset);
}

.area-header,
.capability-label {
  justify-content: space-between;
  gap: var(--space-2);
}

.capability-row {
  display: grid;
  gap: var(--space-2);
  margin-top: var(--space-3);
}

.recommendation-card {
  position: relative;
  display: grid;
  gap: var(--space-3);
  padding: var(--space-4);
  border-color: var(--border-strong);
  border-left-width: 3px;
  color: var(--text-secondary);
}

.recommendation-card.pending {
  background: var(--surface-elevated);
}

.recommendation-card.high {
  border-left-color: var(--status-warning);
}

.recommendation-card.critical {
  border-left-color: var(--status-danger);
}

.recommendation-card.approved {
  border-color: color-mix(in srgb, var(--status-success) 45%, transparent);
}

.recommendation-card.rejected {
  opacity: 0.7;
}

.card-heading {
  justify-content: space-between;
  align-items: flex-start;
  gap: var(--space-3);
}

.severity,
.status-pill,
.chip,
.kind {
  display: inline-flex;
  padding: 2px 6px;
  border: 1px solid var(--border-subtle);
  border-radius: 4px;
  color: var(--text-muted);
}

.cause-line {
  display: grid;
  grid-template-columns: 54px 1fr;
  gap: var(--space-2);
  color: var(--text-muted);
  font-size: 12px;
}

.cause-line span {
  color: var(--text-secondary);
}

.action-list,
.blackbox-list {
  padding: 0;
  margin: 0;
  list-style: none;
}

.action-list li,
.delta-grid,
.comparison-grid {
  display: grid;
  gap: var(--space-2);
}

.delta-grid {
  padding: 0;
  border: 0;
}

.action-list li {
  grid-template-columns: 68px 1fr;
  padding: var(--space-2) 0;
  border-top: 1px solid var(--border-subtle);
}

.delta-grid {
  grid-template-columns: repeat(3, minmax(0, 1fr));
}

.delta-grid span {
  padding: var(--space-2);
  border-radius: 6px;
  background: var(--surface-inset);
  color: var(--text-secondary);
  font-size: 12px;
}

.delta-grid b {
  display: block;
  color: var(--text-muted);
  font-weight: 500;
}

.decision-row {
  flex-wrap: wrap;
}

.empty-state {
  display: flex;
  gap: var(--space-2);
  align-items: center;
  padding: var(--space-4);
  border: 1px dashed var(--border-strong);
  border-radius: 8px;
}

.blackbox-list {
  display: grid;
  gap: var(--space-2);
  max-height: 300px;
  overflow: auto;
}

.calculation-detail {
  display: grid;
  gap: var(--space-3);
  margin-bottom: var(--space-3);
  padding: var(--space-3);
  border: 1px solid var(--border-subtle);
  border-radius: 8px;
  background: var(--surface-inset);
}

.calculation-trigger {
  display: flex;
  gap: var(--space-2);
  align-items: center;
  min-width: 0;
}

.calculation-trigger strong {
  min-width: 0;
  overflow-wrap: anywhere;
  color: var(--text-primary);
  font-size: 12px;
}

.calculation-grid {
  display: grid;
  grid-template-columns: repeat(auto-fit, minmax(132px, 1fr));
  gap: var(--space-2);
}

.calculation-grid span,
.area-calculation-row span {
  min-width: 0;
  padding: var(--space-2);
  border: 1px solid var(--border-subtle);
  border-radius: 6px;
  background: var(--surface-base);
  color: var(--text-secondary);
  font-size: 12px;
}

.area-calculation-row {
  display: flex;
  flex-wrap: wrap;
  gap: var(--space-2);
  min-inline-size: 0;
  margin: 0;
  padding: 0;
  border: 0;
}

.blackbox-row {
  display: grid;
  grid-template-columns: 56px 86px 1fr;
  gap: var(--space-2);
  width: 100%;
  padding: var(--space-2);
  border: 1px solid transparent;
  border-radius: 6px;
  background: transparent;
  color: var(--text-secondary);
  text-align: left;
  cursor: pointer;
}

.blackbox-row.selected,
.blackbox-row:hover {
  border-color: var(--border-strong);
  background: var(--surface-hover);
}

.evaluation-panel {
  min-height: 164px;
}

.comparison-table {
  width: 100%;
  margin-top: var(--space-3);
  border-collapse: collapse;
  color: var(--text-secondary);
  font-size: 13px;
}

.comparison-table th,
.comparison-table td {
  padding: var(--space-2) 0;
  border-bottom: 1px solid var(--border-subtle);
  text-align: left;
}

.comparison-table thead th {
  color: var(--text-muted);
  font-weight: 500;
}

.comparison-table tbody th {
  font-weight: 500;
}

.comparison-table strong,
.ccr-band strong {
  color: var(--text-primary);
}

.ccr-band {
  display: grid;
  grid-template-columns: auto auto 1fr;
  gap: var(--space-3);
  align-items: center;
  margin-top: var(--space-3);
}

.ccr-band span:last-child {
  white-space: nowrap;
}

.decision-history {
  display: grid;
  gap: var(--space-2);
  margin-top: var(--space-4);
  padding-top: var(--space-4);
  border-top: 1px solid var(--border-subtle);
}

.decision-history-title,
.decision-history-row,
.decision-history-empty {
  display: flex;
  align-items: center;
  gap: var(--space-2);
}

.decision-history-title {
  justify-content: space-between;
  color: var(--text-secondary);
}

.decision-history-list {
  display: grid;
  gap: var(--space-2);
  padding: 0;
  margin: 0;
  list-style: none;
}

.decision-history-row,
.decision-history-empty {
  min-height: 34px;
  padding: var(--space-2);
  border: 1px solid var(--border-subtle);
  border-radius: 6px;
  background: var(--surface-inset);
  color: var(--text-secondary);
}

.decision-history-row {
  display: grid;
  grid-template-columns: 60px minmax(0, 1fr) auto;
}

.decision-history-row > span:nth-child(2) {
  min-width: 0;
  overflow: hidden;
  text-overflow: ellipsis;
  white-space: nowrap;
}

.decision-history-empty {
  color: var(--text-muted);
  font-size: 12px;
}

.decision-history-row.approved .status-pill {
  color: var(--status-success);
}

.decision-history-row.rejected .status-pill {
  color: var(--status-danger);
}

.decision-history-row.manual .status-pill {
  color: var(--status-warning);
}

.map-panel {
  min-height: 560px;
}

.cop-frame {
  position: relative;
  margin-top: var(--space-3);
  overflow: hidden;
  border: 1px solid var(--border-subtle);
  border-radius: 8px;
  background: var(--surface-inset);
}

.cop-map {
  display: block;
  width: 100%;
  aspect-ratio: 1.18;
  cursor: grab;
  font-family: var(--font-primary);
  touch-action: none;
  user-select: none;
}

.cop-map.is-panning {
  cursor: grabbing;
}

.map-bg {
  fill: var(--surface-inset);
}

.map-grid-fill {
  fill: url(#grid-major);
  opacity: 0.58;
}

.grid-pattern {
  fill: none;
  stroke: var(--border-subtle);
  stroke-width: 0.35;
}

.grid-axis line {
  stroke: var(--border-subtle);
  stroke-width: 0.18;
}

.route-line {
  fill: none;
  stroke-width: 0.55;
  stroke-linecap: square;
  stroke-dasharray: 3 2;
}

.route-primary {
  stroke: color-mix(in srgb, var(--accent-primary) 72%, transparent);
}

.route-secondary {
  stroke: color-mix(in srgb, var(--status-info) 62%, transparent);
}

.relay-node {
  fill: var(--accent-primary);
  stroke: var(--surface-base);
  stroke-width: 0.65;
}

.sector-fill {
  fill-opacity: 0.14;
  stroke: none;
}

.sector-outline {
  fill: none;
  stroke: var(--border-strong);
  stroke-width: 0.5;
}

.sector-a .sector-fill {
  fill: var(--map-zone-a);
}

.sector-b .sector-fill {
  fill: var(--map-zone-b);
}

.sector-c .sector-fill {
  fill: var(--map-zone-c);
}

.sector.healthy .sector-outline {
  stroke: color-mix(in srgb, var(--status-success) 42%, var(--border-strong));
}

.sector.strained .sector-outline {
  stroke: color-mix(in srgb, var(--status-warning) 58%, var(--border-strong));
}

.sector.deficit .sector-outline {
  stroke: color-mix(in srgb, var(--status-danger) 66%, var(--border-strong));
}

.no-go-area {
  fill: url(#no-go-hatch);
  stroke: var(--status-danger);
  stroke-width: 0.85;
}

.hatch-line {
  stroke: var(--status-danger);
  stroke-width: 0.42;
}

.threat-ring circle {
  fill: none;
  stroke: var(--status-warning);
  stroke-dasharray: 2.5 2;
  stroke-width: 0.55;
}

.map-label,
.map-label-detail,
.map-label-meta,
.asset-label,
.action-path-label {
  font-variant-numeric: tabular-nums;
  paint-order: stroke;
  stroke: var(--surface-inset);
  stroke-width: 1.6;
}

.map-label-layer,
.map-area-label,
.mission-activity-layer,
.action-path-layer {
  pointer-events: none;
}

.map-label {
  fill: var(--text-secondary);
  font-size: 3.1px;
  font-weight: 590;
  text-anchor: middle;
}

.map-label-detail {
  fill: var(--text-primary);
  font-size: 2.15px;
  font-weight: 620;
  text-anchor: middle;
}

.map-label-meta {
  fill: var(--text-muted);
  font-size: 1.72px;
  text-anchor: middle;
}

.mission-activity-path {
  fill: none;
  stroke: color-mix(in srgb, var(--status-info) 46%, transparent);
  stroke-width: 0.44;
  stroke-linecap: round;
}

.action-path {
  fill: none;
  stroke: var(--accent-primary);
  stroke-dasharray: 2.2 1.5;
  stroke-linecap: round;
  stroke-width: 0.9;
  animation: action-path-pulse 1.6s ease-in-out infinite;
}

.action-path-source {
  fill: var(--surface-base);
  stroke: var(--accent-primary);
  stroke-width: 0.55;
}

.action-path-target {
  fill: var(--accent-primary);
  stroke: var(--surface-inset);
  stroke-width: 0.62;
}

.action-path-label {
  fill: var(--text-primary);
  font-size: 2.15px;
  font-weight: 650;
  text-anchor: middle;
}

@keyframes action-path-pulse {
  0%,
  100% {
    opacity: 0.48;
  }

  50% {
    opacity: 1;
  }
}

@media (prefers-reduced-motion: reduce) {
  .action-path {
    animation: none;
  }
}

.asset {
  color: var(--accent-hover);
  outline: none;
}

.asset-hitbox {
  fill: transparent;
  stroke: none;
  pointer-events: all;
}

.asset-ring {
  fill: none;
  stroke: currentColor;
  stroke-width: 0.55;
  opacity: 0.7;
}

.asset-core {
  fill: currentColor;
  stroke: var(--surface-base);
  stroke-width: 0.42;
}

.asset-uav {
  color: var(--accent-hover);
}

.asset-ugv {
  color: var(--status-success);
}

.asset-synthetic {
  color: var(--text-muted);
}

.asset-synthetic .asset-ring {
  opacity: 0.24;
}

.asset.degraded .asset-ring {
  stroke: var(--status-warning);
  stroke-width: 0.75;
}

.asset.stressed .asset-ring,
.asset.lost .asset-ring {
  stroke: var(--status-danger);
  stroke-width: 0.9;
}

.asset.returning,
.asset.standby {
  opacity: 0.62;
}

.asset.lost {
  opacity: 0.38;
}

.asset-label {
  fill: var(--text-secondary);
  font-size: 2.25px;
}

.asset-info {
  opacity: 0;
  pointer-events: none;
  transition: opacity 120ms ease-out;
}

.asset-info-layer {
  pointer-events: none;
}

.asset-info.visible {
  opacity: 1;
}

.asset.asset-active .asset-ring,
.asset:focus .asset-ring,
.asset:hover .asset-ring {
  stroke-width: 0.95;
}

.asset-info-bg {
  fill: color-mix(in srgb, var(--surface-panel) 96%, transparent);
  stroke: var(--border-strong);
  stroke-width: 0.45;
}

.asset-info-title,
.asset-info-line {
  font-variant-numeric: tabular-nums;
  paint-order: stroke;
  stroke: var(--surface-panel);
  stroke-width: 0.7;
}

.asset-info-title {
  fill: var(--text-primary);
  font-size: 2.35px;
  font-weight: 590;
}

.asset-info-line {
  fill: var(--text-secondary);
  font-size: 2.05px;
}

.asset-context-menu {
  position: absolute;
  z-index: 40;
  display: grid;
  gap: var(--space-2);
  width: 228px;
  padding: var(--space-3);
