  gap: var(--space-2);
}

.asset-context-head span {
  display: grid;
  min-width: 0;
}

.asset-context-head strong,
.asset-context-head small,
.asset-context-meta,
.asset-context-note {
  overflow-wrap: anywhere;
}

.asset-context-head strong {
  color: var(--text-primary);
  font-size: 0.84rem;
}

.asset-context-head small,
.asset-context-meta,
.asset-context-note {
