}

.asset-context-note {
  margin: 0;
}

.cop-readout {
  display: grid;
  grid-template-columns: repeat(auto-fit, minmax(112px, 1fr));
  gap: var(--space-2);
  margin-top: var(--space-3);
  min-inline-size: 0;
  padding: 0;
  border: 0;
}

.cop-readout span {
  min-width: 0;
  padding: var(--space-2) var(--space-3);
