}

.builder-message-row {
  display: grid;
  gap: var(--space-1);
}

.builder-error {
  color: var(--status-danger);
  font-size: 12px;
  line-height: 1.35;
}

.builder-meta-grid,
.builder-side-stack {
  display: grid;
  gap: var(--space-3);
}

.builder-intent-grid {
  display: grid;
  gap: var(--space-3);
  padding: var(--space-3);
  border: 1px solid var(--border-subtle);
  border-radius: 8px;
  background: var(--surface-inset);
}

.builder-intent-grid legend {
  padding: 0 var(--space-1);
  color: var(--text-secondary);
  font-size: 12px;
  line-height: 1.35;
}

.builder-field {
  display: grid;
  grid-template-columns: 76px minmax(0, 1fr);
  gap: var(--space-2);
  align-items: center;
  color: var(--text-muted);
  font-size: 12px;
  line-height: 1.35;
}

.builder-field input,
.builder-field select {
  min-width: 0;
  width: 100%;
  min-height: 32px;
  padding: 0 var(--space-2);
  border: 1px solid var(--border-subtle);
  border-radius: 6px;
  background: var(--surface-inset);
  color: var(--text-secondary);
  font: inherit;
}

.builder-checkbox-field {
  grid-template-columns: 76px auto 1fr;
}

.builder-checkbox-field input {
  width: 16px;
  min-height: 16px;
  accent-color: var(--accent-primary);
}

.builder-checkbox-field b {
  color: var(--text-secondary);
  font-size: 12px;
  font-weight: 500;
}

.builder-field input:focus-visible,
.builder-field select:focus-visible,
.flow-node:focus-visible {
  outline: 2px solid var(--accent-hover);
  outline-offset: 2px;
}

.builder-field input[type="range"] {
  padding: 0;
  accent-color: var(--accent-primary);
  background: transparent;
}

.range-field {
  grid-template-columns: 58px minmax(0, 1fr) 40px;
}

.range-field b {
  color: var(--text-secondary);
  font-family:
    Cascadia Mono,
    Berkeley Mono,
    ui-monospace,
    monospace;
  font-size: 12px;
  font-weight: 500;
  text-align: right;
}

.scenario-flow {
  position: relative;
  min-height: 360px;
  overflow: hidden;
  border: 1px solid var(--border-subtle);
  border-radius: 8px;
  background:
    linear-gradient(color-mix(in srgb, var(--surface-elevated) 42%, transparent), transparent),
    var(--surface-inset);
}

.flow-label {
  position: absolute;
  top: var(--space-2);
  left: var(--space-2);
  z-index: 2;
  display: flex;
  gap: var(--space-1);
  align-items: center;
  color: var(--text-muted);
  font-size: 12px;
  line-height: 1.35;
}

.flow-links {
  position: absolute;
  inset: 0;
  width: 100%;
  height: 100%;
  pointer-events: none;
}

.flow-links line {
  stroke: color-mix(in srgb, var(--accent-primary) 58%, transparent);
  stroke-dasharray: 4 3;
  stroke-width: 1.2;
  vector-effect: non-scaling-stroke;
}

.flow-node {
  position: absolute;
  display: grid;
  grid-template-columns: 14px minmax(0, 1fr);
  gap: 1px var(--space-1);
  align-items: center;
  width: 108px;
  min-height: 48px;
  padding: var(--space-2);
  border: 1px solid var(--border-strong);
  border-radius: 6px;
  background: var(--surface-elevated);
  color: var(--text-secondary);
  cursor: grab;
  text-align: left;
  transform: translate(-8%, -50%);
}

.flow-node:active {
  cursor: grabbing;
}

.flow-node.selected {
  border-color: var(--accent-primary);
  color: var(--text-primary);
  background: var(--surface-hover);
}

.flow-node span,
.flow-node small {
  min-width: 0;
  overflow: hidden;
  text-overflow: ellipsis;
  white-space: nowrap;
}

.flow-node span {
  font-size: 12px;
  line-height: 1.25;
}

.flow-node small {
  grid-column: 2;
  color: var(--text-muted);
  font-size: 11px;
  line-height: 1.2;
}

.builder-editor {
  display: grid;
  gap: var(--space-2);
  padding: var(--space-3);
  border: 1px solid var(--border-subtle);
  border-radius: 8px;
  background: var(--surface-inset);
}

.builder-editor-title {
  display: flex;
  gap: var(--space-1);
  align-items: center;
  color: var(--text-secondary);
  font-size: 12px;
  line-height: 1.35;
}

.area-draw-toolbar,
.area-draw-actions {
  display: grid;
  gap: var(--space-2);
}

.area-draw-toolbar {
  grid-template-columns: repeat(3, minmax(0, 1fr));
}

.area-draw-toolbar .button,
.area-draw-actions .button {
  min-width: 0;
  padding-inline: var(--space-2);
  white-space: nowrap;
}

.area-draw-canvas {
  width: 100%;
  aspect-ratio: 100 / 86;
  border: 1px solid var(--border-subtle);
  border-radius: 6px;
  background: var(--surface-panel);
  touch-action: none;
}

.area-draw-canvas.is-drawing {
  cursor: crosshair;
}

.area-draw-bg {
  fill: var(--surface-inset);
}

.area-draw-shape {
  fill: color-mix(in srgb, var(--accent-primary) 14%, transparent);
  stroke: color-mix(in srgb, var(--accent-primary) 58%, transparent);
  stroke-width: 0.9;
  vector-effect: non-scaling-stroke;
}

.area-draw-shape.selected {
  fill: color-mix(in srgb, var(--status-warning) 18%, transparent);
  stroke: var(--status-warning);
}

.area-draw-draft {
  fill: none;
  stroke: var(--status-info);
  stroke-dasharray: 2 1.5;
  stroke-width: 1;
  vector-effect: non-scaling-stroke;
}

.area-draw-canvas circle {
  fill: var(--status-info);
}

@media (max-width: 820px) {
  .builder-command-row {
    grid-template-columns: 1fr;
  }

  .area-draw-toolbar,
  .area-draw-actions {
    grid-template-columns: 1fr;
  }
}

.graph-editor {
  gap: var(--space-3);
}

.graph-action-grid,
.edge-compose {
  display: grid;
  gap: var(--space-2);
}

.graph-action-grid {
  grid-template-columns: repeat(2, minmax(0, 1fr));
}

.graph-action-grid .button,
.edge-compose .button {
  min-width: 0;
  padding-inline: var(--space-2);
  white-space: nowrap;
}

.edge-compose {
