}

.edge-list {
  display: grid;
  gap: var(--space-2);
  max-height: 168px;
  margin: 0;
  overflow: auto;
  padding: 0;
  padding-right: 2px;
  list-style: none;
}

.edge-row {
  display: grid;
  grid-template-columns: minmax(0, 1fr) 34px;
  gap: var(--space-2);
  align-items: center;
  min-height: 34px;
  padding: var(--space-1) var(--space-2);
  border: 1px solid var(--border-subtle);
  border-radius: 6px;
  background: var(--surface-panel);
}

.edge-row span {
  overflow: hidden;
  color: var(--text-secondary);
  font-size: 12px;
  line-height: 1.35;
  text-overflow: ellipsis;
  white-space: nowrap;
}

.edge-row .button {
  width: 30px;
  min-height: 28px;
  padding: 0;
}

.builder-hint {
  color: var(--text-muted);
  font-size: 12px;
  line-height: 1.45;
}

.flow-links path,
.flow-links marker path {
  fill: color-mix(in srgb, var(--accent-primary) 70%, transparent);
}

.flow-links line {
  marker-end: url("#flow-arrow");
}

.flow-node.connect-source {
