}

.flow-node.connect-target {
  border-style: dashed;
}

.flow-node b {
  grid-column: 1;
  grid-row: 2;
  color: var(--accent-primary);
  font-family:
    Cascadia Mono,
    Berkeley Mono,
    ui-monospace,
    monospace;
  font-size: 10px;
  font-weight: 500;
  line-height: 1;
