  font-family: var(--font-primary);
  color: var(--text-primary);
  background: var(--surface-base);
  font-synthesis: none;
  text-rendering: optimizeLegibility;
  -webkit-font-smoothing: antialiased;
  --surface-base: #0b0c0d;
  --surface-panel: #111315;
  --surface-elevated: #17191b;
  --surface-inset: #08090a;
  --surface-hover: #1d2023;
  --surface-command: rgba(255, 255, 255, 0.035);
  --rail-muted: rgba(255, 255, 255, 0.1);
  --text-primary: #f0f2ec;
  --text-secondary: #b9bfb8;
  --text-muted: #7f877f;
  --border-subtle: rgba(255, 255, 255, 0.06);
  --border-strong: rgba(255, 255, 255, 0.14);
  --accent-primary: #b9c56a;
  --accent-hover: #d0dc80;
